INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('public-health-specialist-moex-00237', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '有關於病例對照研究設計，下列敘述何者錯誤？', '["此研究設計無法評估疾病率", "此法如透過問卷收集發病前的疾病相關危險因子，則暴露與疾病的因果關係明確", "病例組中由於某些特殊暴露會導致其受到更頻繁的醫療照護，進而使得疾病發生率和檢出率 較高，導致暴露與疾病間的相關性甚高。此即所謂的醫療監視偏差（medicalsurveillancebias）", "病例對照研究法可能會有回憶偏差產生，如果回憶偏差在病例和對照兩組的發生比例一致， 會產生無差異性的錯分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00238', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列何者為疾病「年代效應（periodeffect）」之特性？', '["影響同一年齡組在不同時期的健康狀況", "影響不同年齡組在同一時期的健康狀況", "影響不同世代在相同年齡時的健康狀況", "影響同一世代在不同年齡時的健康狀況"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00239', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列有關實驗流行病學之敘述，何者錯誤？', '["介入性研究通常會需要比觀察性研究較高的研究成本", "隨機對照試驗（Randomized Controlled Trial）是實驗流行病學中經常用來提供可靠因果相 關證據的方法之一", "雙盲試驗目的是為了讓計畫主持人和訪視者皆不清楚研究對象屬於實驗組或對照組，使不 至於產生結果偏差", "有對照的隨意分配（controlledarbitraryallocation）研究設計，即使透過資料分析儘可能考 慮可能的干擾，然而對於未知的干擾可能無法評估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00240', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在一個探討飲酒和肝硬化的世代研究中，發現飲酒者肝硬化的發生率為8/1,000，而不飲酒者 肝硬化的發生率為2/1,000。另有調查顯示，該族群中有40%是飲酒者，則該族群中肝硬化的 發生率可歸因於飲酒的比例為何？', '["75%", "64%", "60%", "55%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00241', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於回溯性世代研究，下列敘述何者正確？', '["可以計算發生率", "暴露測量通常可以被標準化", "需要等很長的時間才能得到結果", "容易有回憶偏差（recallbias）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00242', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於病例交叉設計（case-crossoverdesign），下列何者錯誤？', '["適用於探討急性發作的疾病", "適用於探討暴露短暫且會隨時間變化的暴露", "因為每一個病例同時也是自己的對照，因此可以控制會隨時間變化的干擾因子", "如果暴露的測量是使用參與研究者的自述（self-report），則容易有回憶偏差（recallbias）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00243', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '在估計臨床試驗所需的樣本數時，下列何種條件會導致樣本數增加？', '["兩個治療組治癒率的差異增加", "使用單尾檢定取代雙尾檢定", "願意增加犯第I型錯誤（type1error）的風險", "兩個治療組中有較低治癒率的組別治癒率增加"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00244', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某一世代研究在長期追蹤過程中，研究對象失去追蹤情形嚴重，導致疾病相關性指標之估計值與 真值產生偏差。若估計之累積發生率比（riskratio）為0.2，真值為0.5，試問此偏差方向為何？', '["趨零偏差（towardthenull）", "離零偏差（awayfromthenull）", "相反偏差（switchoverbias）", "隨機誤差（randomerror）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00245', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某研究使用巢式病例對照研究（nestedcase-controlstudy），探討砷與皮膚癌的關係，但因檢體 已存放多年，所以砷濃度檢驗並不準確，這是屬於那一種偏差？', '["差別性分類錯誤（differentialmisclassification）", "無差別性分類錯誤（nondifferentialmisclassification）", "偵測錯誤（detectionbias）", "選樣偏差（selectionbias）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00246', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '下列何項方法無法減少流行病學研究中選樣偏差（selectionbias）？', '["增加樣本數", "增加回應率（responserate）", "採用新發病病例而非盛行病例", "進行基於族群的病例對照研究，而非基於醫院的病例對照研究"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL)
